if (typeof candidates === 'string') { try { candidates = JSON.parse(candidates); } catch { candidates = []; } }
if (!Array.isArray(candidates) || candidates.length === 0) return [];
return [{ json: { ...$json, candidates } }];

parameters.text:
=Ти будуєш граф знань Inbox Agent. Порівняй цільовий запис із кандидатами та поверни лише обґрунтовані зв’язки за JSON-схемою.

Типи:
- duplicate: фактично той самий матеріал або файл;
- references: один матеріал прямо посилається на інший;
- supports: один матеріал дає докази, реалізацію або корисне доповнення до іншого;
- contradicts: твердження суттєво суперечать одне одному;
- similar: зміст близький, але сильніший тип не доведено.

Не вигадуй зв’язків. Для supports/references вкажи напрямок. Пояснення пиши українською, максимум 180 символів. Не повертай слабкі збіги лише через загальну категорію. Якщо hard_relation заданий, збережи цей тип і напрямок.

Ціль:
{{ JSON.stringify($json.target) }}

Кандидати:
{{ JSON.stringify($json.candidates) }}

parameters.jsCode:
const source = $('Pass Candidate Set').first().json;
const targetId = String(source.target_knowledge_id);
const candidates = new Map(source.candidates.map((candidate) => [String(candidate.id), candidate]));
const output = $json.output || $json;
const judged = Array.isArray(output.relations) ? output.relations : [];
const byId = new Map(judged.map((relation) => [String(relation.candidate_id), relation]));
const relations = [];
for (const [candidateId, candidate] of candidates) {
  let relation = byId.get(candidateId);
  if (candidate.hard_relation) {
    relation = { candidate_id: candidateId, relation_type: candidate.hard_relation, direction: candidate.reference_direction || 'target_to_candidate', score: candidate.hard_relation === 'duplicate' ? 0.99 : Math.max(Number(candidate.heuristic_score || 0), 0.85), explanation: candidate.hard_relation === 'duplicate' ? 'Однаковий файл, контрольна сума або URL джерела.' : 'Виявлено пряме посилання між матеріалами.' };
  } else if (!relation && Number(candidate.heuristic_score || 0) >= 0.55) {
    relation = { candidate_id: candidateId, relation_type: 'similar', direction: 'target_to_candidate', score: Number(candidate.heuristic_score), explanation: 'Збігаються проєкт, категорія, тип або кілька тегів.' };
  }
  if (!relation) continue;
  const type = String(relation.relation_type || '');
  const score = Math.max(0, Math.min(1, Number(relation.score || 0)));
  if (!['similar','supports','contradicts','references','duplicate'].includes(type)) continue;
  if (!candidate.hard_relation && score < (type === 'similar' ? 0.45 : 0.55)) continue;
  let sourceId = targetId;
  let destinationId = candidateId;
  if (['similar','duplicate','contradicts'].includes(type)) {
    [sourceId, destinationId] = [targetId, candidateId].sort();
  } else if (relation.direction === 'candidate_to_target') {
    sourceId = candidateId; destinationId = targetId;
  }
  relations.push({ source_item_id: sourceId, target_item_id: destinationId, relation_type: type, score, explanation: String(relation.explanation || '').slice(0, 300) });
}
const unique = [...new Map(relations.map((relation) => [`${relation.source_item_id}:${relation.target_item_id}:${relation.relation_type}`, relation])).values()];
return [{ json: { target_knowledge_id: targetId, target_inbox_item_id: source.target_inbox_item_id, relations: unique } }];
